function(){
  // Usa o GA Client ID como external_id (remove prefixo GA1.X.)
  // Com null-check para nao quebrar em visitantes novos
  var gaId = {{[CT] [VAR] user_id}};
  if (gaId && typeof gaId === 'string') {
    // Remove prefixo "GA1.X." de forma robusta
    var cleaned = gaId.replace(/^GA\d+\.\d+\./, '');
    if (cleaned) return cleaned;
  }
  // Fallback: usa _fbp como external_id (sempre definido pelo pixel)
  var fbp = {{[CT] [VAR] fbp}};
  if (fbp && typeof fbp === 'string') return fbp;
  return undefined;
}

