const hmacSha256 = require('hmacSha256');
const getRequestBody = require('getRequestBody');
const logToConsole = require('logToConsole');

const keyId = data.keyId || 'n8n_key';
const outputEncoding = data.outputEncoding || 'hex';

const body = getRequestBody() || '';

const signature = hmacSha256(body, keyId, { outputEncoding: outputEncoding });

if (!signature) {
  logToConsole('[n8n-hmac-signature] hmacSha256 retornou null/undefined. Confirmar SGTM_CREDENTIALS env file montado em /etc/sgtm-keys/keys.json com key "' + keyId + '"');
  return '';
}

return signature;


